VALUES
  ('elementary-c5fb3965-moex-00140', 'elementary-c5fb3965', 'elementary-c5fb3965-moex-114-bdc7da1c', 'sub-elementary-c5fb3965-03', NULL, 'single_choice', '依姓名條例及其施行細則規定，戶政事務所受理14歲以上國民申請更改姓名者，應查詢有無下列何種情事？', '["是否經通緝或羈押", "是否與經通緝有案之人犯姓名完全相同", "更改後姓名是否粗俗不雅", "更改後姓名是否與三親等以內直系尊親屬姓名完全相同"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:05+00:00", "source_pdf_sha1": "f19cf4640384", "answer_pdf_sha1": "3b4f60409dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "503", "s": "0203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "戶政"}'::jsonb, NULL),
  ('elementary-c5fb3965-moex-00141', 'elementary-c5fb3965', 'elementary-c5fb3965-moex-114-bdc7da1c', 'sub-elementary-c5fb3965-03', NULL, 'single_choice', '關於遷出登記，下列敘述何者錯誤？', '["遷出原鄉（鎮、市、區）3個月以上，應為遷出登記", "因服兵役，得不為遷出登記", "全戶遷徙時，矯正機關收容人得不為遷徙登記", "全戶遷離戶籍地，未於法定期間申請遷徙登記，無法催告，經房屋所有權人申請時，戶政事務所得將其 全戶戶籍暫遷至該戶政事務所"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:05+00:00", "source_pdf_sha1": "f19cf4640384", "answer_pdf_sha1": "3b4f60409dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "503", "s": "0203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "戶政"}'::jsonb, NULL),
  ('elementary-c5fb3965-moex-00142', 'elementary-c5fb3965', 'elementary-c5fb3965-moex-114-bdc7da1c', 'sub-elementary-c5fb3965-03', NULL, 'single_choice', '下列有關國民身分證之敘述，何者錯誤？', '["用以辨識個人身分，效用及於全國", "應隨身攜帶", "因申請補領而掛失完成後即永久失效", "因行政區域調整而未全面換發前仍有效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:05+00:00", "source_pdf_sha1": "f19cf4640384", "answer_pdf_sha1": "3b4f60409dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "503", "s": "0203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "戶政"}'::jsonb, NULL),
  ('elementary-c5fb3965-moex-00143', 'elementary-c5fb3965', 'elementary-c5fb3965-moex-114-bdc7da1c', 'sub-elementary-c5fb3965-03', NULL, 'single_choice', '關於外國人依國籍法第3條申請歸化之要件，下列敘述何者正確？', '["申請人未滿18歲即可申請", "申請人在臺灣地區就學居留滿2年，畢業後改為應聘居留滿3年，即得申請歸化", "申請人取得女子美髮技術士證照，符合有相當之財產或專業技能，足以自立，或生活保障無虞之歸化條件", "申請人曾犯詐欺罪，於警察刑事紀錄證明載有犯罪紀錄者，亦得申請歸化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:05+00:00", "source_pdf_sha1": "f19cf4640384", "answer_pdf_sha1": "3b4f60409dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "503", "s": "0203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "戶政"}'::jsonb, NULL),
  ('elementary-c5fb3965-moex-00144', 'elementary-c5fb3965', 'elementary-c5fb3965-moex-114-bdc7da1c', 'sub-elementary-c5fb3965-03', NULL, 'single_choice', '山地原住民係指臺灣光復前原籍在山地行政區域內，並於何者登記其本人或直系血親尊親屬屬於原住民者？', '["國民身分證", "戶口普查紀錄", "戶籍謄本", "戶口調查簿"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:05+00:00", "source_pdf_sha1": "f19cf4640384", "answer_pdf_sha1": "3b4f60409dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "503", "s": "0203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "戶政"}'::jsonb, NULL),
  ('elementary-c5fb3965-moex-00145', 'elementary-c5fb3965', 'elementary-c5fb3965-moex-114-bdc7da1c', 'sub-elementary-c5fb3965-03', NULL, 'single_choice', '甲有一子乙8歲，從父姓，甲申請改姓。依姓名條例之規定，關於乙之戶籍資料，下列敘述何者正確？', '["甲為乙之法定代理人，甲須同時向戶政機關提出乙之改姓申請", "戶政機關於更改甲之姓氏後，依職權通知乙另行提出改姓之申請", "戶政機關於更改甲之姓氏時，同時依職權更改乙戶籍資料之父之姓氏，並通知乙", "戶政機關於更改甲之姓氏後，依職權通知甲之配偶提出乙之改姓申請"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:05+00:00", "source_pdf_sha1": "f19cf4640384", "answer_pdf_sha1": "3b4f60409dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "503", "s": "0203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "戶政"}'::jsonb, NULL),
  ('elementary-c5fb3965-moex-00146', 'elementary-c5fb3965', 'elementary-c5fb3965-moex-114-55d283b0', 'sub-elementary-c5fb3965-04', NULL, 'single_choice', '下列關於法源的敘述，何者錯誤？', '["憲法為國家的根本大法，規範政府組織及人民的權利義務", "法律經立法機關通過後，不待總統公布，即可發生效力", "命令係指行政機關基於法律授權或職權，所發布之規章，必須要注意不得超越母法的規定", "憲法、法律、命令等位階，憲法的位階最高，法律次之，命令最低"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:06+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "戶政"}'::jsonb, NULL),
  ('elementary-c5fb3965-moex-00147', 'elementary-c5fb3965', 'elementary-c5fb3965-moex-114-55d283b0', 'sub-elementary-c5fb3965-04', NULL, 'single_choice', '上級政府或主管機關，對於下級政府或機關所陳報之事項，加以審查，並作成決定，以完成該事項之法定 效力。上級政府或主管機關之行為，稱為：', '["考核", "備查", "監督", "核定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:06+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "戶政"}'::jsonb, NULL),
  ('elementary-c5fb3965-moex-00148', 'elementary-c5fb3965', 'elementary-c5fb3965-moex-114-55d283b0', 'sub-elementary-c5fb3965-04', NULL, 'single_choice', '下列有關擴張與限縮解釋的敘述，何者錯誤？', '["擴張解釋與限縮解釋，都是以文義的可能範圍為界限", "憲法第8條人民身體之自由應予保障，所稱人民指自然人，即為限縮解釋", "處罰或課予人民義務之規定文字，應從嚴解釋，不得任意擴張", "例外規定應為擴張解釋，否則有失其規定之旨"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:06+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "戶政"}'::jsonb, NULL),
  ('elementary-c5fb3965-moex-00149', 'elementary-c5fb3965', 'elementary-c5fb3965-moex-114-55d283b0', 'sub-elementary-c5fb3965-04', NULL, 'single_choice', '下列何者不是形成權？', '["甲、乙二人共有一筆土地，因協議分割不成，甲提起訴訟，請求法院為裁判分割", "甲售予車輛於乙，惟該車有瑕疵，乙向甲主張減少價金", "甲與乙成立買賣契約，甲未給付價金，15年後乙向甲請求給付價金，甲主張已超過15年，拒絕給付價金", "甲與乙成立買賣契約，但乙未於期限內給付，甲向乙解除契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:06+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "戶政"}'::jsonb, NULL)
